class LFUCache {
public:
    LFUCache(int capacity) : capacity_(capacity), minFreq_(0) {
        keyToVal_.reserve(capacity);
        keyToFreq_.reserve(capacity);
        freqToKeys_.reserve(capacity);
    }

    int get(int key) {
        if (!keyToVal_.count(key)) return -1;
        int count = keyToFreq_[key];
        keyToFreq_.erase(key);
        freqToKeys_[count].erase(key);
        if (freqToKeys_[count].empty()) freqToKeys_.erase(count);
        keyToFreq_[key] = count + 1;
        freqToKeys_[count + 1].insert(key);
        return keyToVal_[key];
    }

    void put(int key, int value) {
        if (!capacity_) return;
        if (keyToVal_.count(key)) {
            keyToVal_[key] = value;
            get(key);
            return;
        }
        if (keyToVal_.size() == capacity_) {
            int evict = *freqToKeys_[minFreq_].begin();
            keyToVal_.erase(evict);
            keyToFreq_.erase(evict);
            freqToKeys_[minFreq_].erase(evict);
            if (freqToKeys_[minFreq_].empty()) freqToKeys_.erase(minFreq_);
        }
        keyToVal_[key] = value;
        keyToFreq_[key] = 1;
        freqToKeys_[1].insert(key);
        minFreq_ = 1;
    }

private:
    int capacity_;
    int minFreq_;
    unordered_map<int, int> keyToVal_;
    unordered_map<int, int> keyToFreq_;
    unordered_map<int, unordered_set<int>> freqToKeys_;
};
